1. #!/usr/bin/env node
2. import path from 'node:path';
3. import { parseArgs } from 'node:util';
4. import {
5.   ensureDir,
6.   findVariant,
7.   loadModelsConfig,
8.   loadTask,
9.   loadVariantsConfig,
10.   resolveTimeoutMs,
11.   ROOT_DIR,
12.   runCommand,
13.   truncateText,
14.   writeJson,
15.   writeText
16. } from './lib.mjs';
17. 
18. const { values } = parseArgs({
19.   options: {
20.     task: { type: 'string' },
21.     variant: { type: 'string' },
22.     'run-dir': { type: 'string' },
23.     worktree: { type: 'string' },
24.     'base-sha': { type: 'string' },
25.     'start-model': { type: 'string' },
26.     'reasoning-effort': { type: 'string' },
27.     'dry-run': { type: 'boolean', default: false },
28.     help: { type: 'boolean', short: 'h' }
29.   }
30. });
31. 
32. if (values.help || !values.task || !values.variant || !values['run-dir'] || !values.worktree) {
33.   console.log(JSON.stringify({
34.     usage: 'node eval/scripts/run-variant.mjs --task <task-id|path> --variant <router|fixed> --run-dir <dir> --worktree <dir> --base-sha <sha> [--start-model <id>] [--reasoning-effort medium] [--dry-run]'
35.   }, null, 2));
36.   process.exit(values.help ? 0 : 1);
37. }
38. 
39. const modelsConfig = await loadModelsConfig();
40. const variants = await loadVariantsConfig();
41. const variant = findVariant(variants, values.variant);
42. const task = await loadTask(values.task);
43. const runDir = path.resolve(ROOT_DIR, values['run-dir']);
44. const worktreePath = path.resolve(ROOT_DIR, values.worktree);
45. const startModel = values['start-model'] ?? modelsConfig.implementationStartModel.id;
46. const reasoningEffort = values['reasoning-effort'] ?? modelsConfig.implementationStartModel.reasoningEffort ?? 'medium';
47. const timeoutMs = resolveTimeoutMs('copilot', {
48.   modelsConfig,
49.   overrideMs: task.timeoutMs ?? variant.timeoutMs
50. });
51. 
52. await ensureDir(runDir);
53. 
54. const args = [
55.   '-p',
56.   task.prompt,
57.   '--model',
58.   startModel,
59.   '--reasoning-effort',
60.   reasoningEffort,
61.   '--output-format',
62.   'json',
63.   '--stream',
64.   'off',
65.   '--allow-all',
66.   '--no-ask-user'
67. ];
68. 
69. if (variant.autopilot) {
70.   args.push('--autopilot');
71. }
72. if (variant.experimental) {
73.   args.push('--experimental');
74. }
75. if (variant.includePluginDir) {
76.   args.push('--plugin-dir', worktreePath);
77. }
78. 
79. const commandSummary = {
80.   cwd: worktreePath,
81.   command: 'copilot',
82.   args,
83.   startModel,
84.   reasoningEffort,
85.   variantId: variant.id,
86.   taskId: task.id,
87.   timeoutMs,
88.   dryRun: values['dry-run']
89. };
90. await writeJson(path.join(runDir, 'run-command.json'), commandSummary);
91. 
92. if (values['dry-run']) {
93.   const dryRunResult = {
94.     ...commandSummary,
95.     exitCode: 0,
96.     signal: null,
97.     timedOut: false,
98.     errorCode: null,
99.     errorMessage: null,
100.     stdoutBytes: 0,
101.     stderrBytes: 0,
102.     changedFiles: [],
103.     diffBytes: 0,
104.     statusPreview: '',
105.     runStatus: 'dry-run',
106.     skipped: true,
107.     reason: 'dry-run',
108.     dryRun: true
109.   };
110.   await writeText(path.join(runDir, 'copilot-output.jsonl'), '');
111.   await writeText(path.join(runDir, 'copilot-stderr.txt'), '');
112.   await writeText(path.join(runDir, 'changed-files.txt'), '');
113.   await writeText(path.join(runDir, 'git-diff.patch'), '');
114.   await writeText(path.join(runDir, 'git-status.txt'), '');
115.   await writeJson(path.join(runDir, 'run-result.json'), dryRunResult);
116.   console.log(JSON.stringify(dryRunResult, null, 2));
117.   process.exit(0);
118. }
119. 
120. const runResult = runCommand('copilot', args, { cwd: worktreePath, timeout: timeoutMs });
121. await writeText(path.join(runDir, 'copilot-output.jsonl'), runResult.stdout);
122. await writeText(path.join(runDir, 'copilot-stderr.txt'), runResult.stderr);
123. 
124. // Use base-sha for diff to capture all changes since the worktree's base commit
125. // This handles both staged and unstaged changes, and works even if changes were committed
126. const baseSha = values['base-sha'] || 'HEAD';
127. const changedFilesResult = runCommand('git', ['diff', '--name-only', `${baseSha}...HEAD`], { cwd: worktreePath });
128. const diffResult = runCommand('git', ['diff', '--binary', `${baseSha}...HEAD`], { cwd: worktreePath });
129. const statusResult = runCommand('git', ['status', '--short'], { cwd: worktreePath });
130. 
131. await writeText(path.join(runDir, 'changed-files.txt'), changedFilesResult.stdout);
132. await writeText(path.join(runDir, 'git-diff.patch'), diffResult.stdout);
133. await writeText(path.join(runDir, 'git-status.txt'), statusResult.stdout);
134. 
135. const summary = {
136.   ...commandSummary,
137.   exitCode: runResult.status,
138.   signal: runResult.signal,
139.   timedOut: runResult.timedOut,
140.   errorCode: runResult.error?.code ?? null,
141.   errorMessage: runResult.error?.message ?? null,
142.   stdoutBytes: Buffer.byteLength(runResult.stdout, 'utf8'),
143.   stderrBytes: Buffer.byteLength(runResult.stderr, 'utf8'),
144.   changedFiles: changedFilesResult.stdout.split(/\r?\n/).filter(Boolean),
145.   diffBytes: Buffer.byteLength(diffResult.stdout, 'utf8'),
146.   statusPreview: truncateText(statusResult.stdout, 1000),
147.   runStatus: runResult.timedOut ? 'timed_out' : (runResult.ok ? 'completed' : 'failed')
148. };
149. 
150. await writeJson(path.join(runDir, 'run-result.json'), summary);
151. console.log(JSON.stringify(summary, null, 2));
152.

