44. function computeRelativeCostIndex({ modelsConfig, artifactSummary, runSummary }) {
45.   const observedModels = unique([...(artifactSummary.modelMentions ?? []), runSummary.startModel]);
46.   const effectiveWeight = Math.max(...observedModels.map((modelId) => getModelWeight(modelsConfig, modelId)));
47.   const routePenalty = 1 + Math.max(0, observedModels.length - 1) * (modelsConfig.relativeCostIndex?.routeSwitchPenalty ?? 0);
48.   const effortMultiplier = getEffortMultiplier(modelsConfig, runSummary.reasoningEffort);
49.   const observedUsage = deriveObservedUsage(artifactSummary);
50. 
