52.     const totalTokens = observedUsage.reduce((sum, candidate) => sum + (candidate.totalTokens ?? 0), 0);
53.     return {
54.       mode: 'observed_tokens_weighted',
55.       effectiveWeight,
56.       routePenalty,
57.       effortMultiplier,
58.       observedUsage,
59.       value: Number((((totalTokens / 1000) || 0.1) * effectiveWeight * routePenalty * effortMultiplier).toFixed(3))
60.     };
61.   }
62. 
63.   const visibleUnitBytes = modelsConfig.relativeCostIndex?.visibleUnitBytes ?? 1024;
64.   const visibleBytes = Math.max(
65.     artifactSummary.rawStdoutBytes ?? 0,
66.     (artifactSummary.gitDiffBytes ?? 0) + Buffer.byteLength(artifactSummary.finalResponseSnippet ?? '', 'utf8')
67.   );
68. 
