147. async function invokeJudgeWithRetry(args, options, maxRetries = 2) {
148.   let lastResult = null;
149.   let lastError = null;
150. 
151.   for (let attempt = 0; attempt <= maxRetries; attempt++) {
152.     console.error(`[Judge] Attempt ${attempt + 1}/${maxRetries + 1}...`);
153.     try {
154.       const result = runCommand('copilot', args, options);
155.       const stdout = result.stdout?.trim() ?? '';
156.       const hasOutput = stdout.length > 0;
