160. 
161.       if (hasOutput && !isTimeout) {
162.         return result;
163.       }
164. 
165.       lastResult = result;
166.       if (attempt < maxRetries) {
167.         const delayMs = Math.pow(2, attempt) * 3000;
168.         console.error(`[Judge] Retrying in ${delayMs}ms...`);
169.         await new Promise((resolve) => setTimeout(resolve, delayMs));
170.       }
171.     } catch (err) {
172.       lastError = err;
173.       console.error(`[Judge] Error: ${err.message}`);
174.       if (attempt < maxRetries) {
175.         const delayMs = Math.pow(2, attempt) * 3000;
176.         console.error(`[Judge] Retrying in ${delayMs}ms...`);
177.         await new Promise((resolve) => setTimeout(resolve, delayMs));
178.       }
179.     }
180.   }
