     effectiveWeight,
     routePenalty,
     effortMultiplier,
     visibleBytes,
     visibleUnitBytes,
     observedUsage: [],
     value: Number((Math.max(visibleBytes / visibleUnitBytes, 0.1) * effectiveWeight * routePenalty * effortMultiplier).toFixed(3))
